import{_ as l,c as i,o as a,ag as t}from"./chunks/framework.C86mscM5.js";const r="/fe-handbook/assets/image-20250815155437416.HagIfUhl.png",f=JSON.parse('{"title":"esbuild","description":"","frontmatter":{},"headers":[],"relativePath":"build-tools/bundler/esbuild.md","filePath":"build-tools/bundler/esbuild.md","lastUpdated":1776520529000}'),s={name:"build-tools/bundler/esbuild.md"};function o(n,e,u,d,b,h){return a(),i("div",null,e[0]||(e[0]=[t('<h1 id="esbuild" tabindex="-1"><a href="https://esbuild.github.io/" target="_blank" rel="nofollow noopener noreferrer">esbuild</a> <a class="header-anchor" href="#esbuild" aria-label="Permalink to &quot;[esbuild](https://esbuild.github.io/)&quot;">​</a></h1><ul><li>written in Go</li></ul><h2 id="why-is-esbuild-fast" tabindex="-1"><a href="https://esbuild.github.io/faq/#why-is-esbuild-fast" target="_blank" rel="nofollow noopener noreferrer">Why is esbuild fast?</a> <a class="header-anchor" href="#why-is-esbuild-fast" aria-label="Permalink to &quot;[Why is esbuild fast?](https://esbuild.github.io/faq/#why-is-esbuild-fast)&quot;">​</a></h2><ul><li>It&#39;s written in Go and compiles to native code.</li><li>Parallelism is used heavily.</li><li>Everything in esbuild is written from scratch.</li><li>Memory is used efficiently.</li></ul><blockquote><ul><li><strong>Go 语言优势</strong>：esbuild 由 Go 编写并编译为原生代码，而多数其他打包工具基于 JavaScript。JS 工具每次运行需 JIT 解析，而 esbuild 可直接执行，且 Go 天生支持线程内存共享，并行效率远超 JS（JS 线程需数据序列化，垃圾回收也更占资源）。</li><li><strong>高度并行化</strong>：内部算法设计充分利用 CPU 核心，解析和代码生成阶段（占主要工作）完全并行，多入口点共享相同库时可高效分配工作。</li><li><strong>自研组件</strong>：未使用第三方库，从设计初期注重性能，数据结构一致避免转换开销。例如，自研 TypeScript 解析器避免官方 TS 编译器的低效（如多态对象、动态属性访问、不必要的类型检查）。</li><li><strong>高效内存使用</strong>：AST 仅经 3 次处理（词法分析 / 解析、绑定 / 转换、压缩 / 生成代码），最大化 CPU 缓存利用；Go 的内存布局紧凑（如布尔值占 1 字节，对象嵌入避免额外分配），比 JS 更高效。</li></ul></blockquote><h2 id="为什么生产不用esbuild" tabindex="-1">为什么生产不用esbuild？ <a class="header-anchor" href="#为什么生产不用esbuild" aria-label="Permalink to &quot;为什么生产不用esbuild？&quot;">​</a></h2><p><img src="'+r+'" alt="image-20250815155437416"></p><h2 id="bundle-size-analyzer" tabindex="-1"><a href="https://esbuild.github.io/analyze/" target="_blank" rel="nofollow noopener noreferrer">Bundle Size Analyzer</a> <a class="header-anchor" href="#bundle-size-analyzer" aria-label="Permalink to &quot;[Bundle Size Analyzer](https://esbuild.github.io/analyze/)&quot;">​</a></h2><ul><li>Treemap Chart 👍</li><li>Sunburst Chart</li><li>Flame Chart</li></ul><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li><a href="https://juejin.cn/column/7285233095058718756" target="_blank" rel="nofollow noopener noreferrer">https://juejin.cn/column/7285233095058718756</a></li></ul>',11)]))}const p=l(s,[["render",o]]);export{f as __pageData,p as default};
